# --- 2. THE HEALED NODE BRIDGE ---
def get_hydra_w3():
    endpoints = [os.getenv("RPC_URL"), "https://polygon-rpc.com", "https://1rpc.io/matic"]
    for url in endpoints:
        if not url: continue
        try:
            _w3 = Web3(Web3.HTTPProvider(url.strip(), request_kwargs={'timeout': 10}))
            if _w3.is_connected():
                _w3.middleware_onion.inject(ExtraDataToPOAMiddleware, layer=0)
                return _w3
        except: continue
    return None

w3 = get_hydra_w3()
if not w3: exit("FATAL: RPC Failure.")

usdc_e_contract = w3.eth.contract(address=USDC_E, abi=ERC20_ABI)

def get_vault():
    seed = os.getenv("WALLET_SEED", "").strip()
    Account.enable_unaudited_hdwallet_features()
    try:
        return Account.from_mnemonic(seed) if " " in seed else Account.from_key(seed)
    except: return None

vault = get_vault()

def init_clob():
    try:
        funder = Web3.to_checksum_address(os.getenv("FUNDER_ADDRESS", vault.address))
        client = ClobClient(
            host="https://clob.polymarket.com", 
            key=vault.key.hex(), 
            chain_id=137, 
            signature_type=int(os.getenv("SIGNATURE_TYPE", 1)), 
            funder=funder
        )
        client.set_api_creds(client.create_or_derive_api_creds())
        return client
    except: return None

clob_client = init_clob()

# --- 3. THE PRICE & ARBI CORE ---
async def get_safe_price(token_id):
    """Fetches real-time price + slippage to satisfy 0.01-0.99 API requirement."""
    try:
        url = f"https://clob.polymarket.com/book?token_id={token_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        data = r.json()
        if data.get('asks'):
            best_ask = float(data['asks'][0]['price'])
            return min(0.99, round(best_ask * 1.02, 2))
    except: pass
    return 0.99

def calculate_arbitrage_guaranteed(p_yes, p_no, total_capital):
    combined_prob = p_yes + p_no
    if combined_prob <= 0: return None
    stake_yes = np.floor(((p_no / combined_prob) * total_capital) * 100) / 100
    stake_no = np.floor(((p_yes / combined_prob) * total_capital) * 100) / 100
    if stake_yes < 1.0 or stake_no < 1.0: return None
    roi = round(((1 / combined_prob) - 1) * 100, 2)
    return {"stake_yes": stake_yes, "stake_no": stake_no, "roi": roi}

async def fetch_full_market(cond_id):
    try:
        url = f"https://clob.polymarket.com/markets/{cond_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        d = r.json()
        return {t['outcome'].upper(): {"id": t['token_id'], "price": float(t['price'])} for t in d.get('tokens', [])}
    except: return None

async def scour_arbitrage():
    global ARBI_CACHE
    ARBI_CACHE = []
    tags = [1, 10, 100, 4, 6, 237]
    for tag in tags:
        url = f"https://gamma-api.polymarket.com/events?active=true&closed=false&limit=10&tag_id={tag}"
        try:
            resp = await asyncio.to_thread(requests.get, url, timeout=5)
            for e in resp.json():
                m = e.get('markets', [])
                if not m: continue
                m_data = await fetch_full_market(m[0]['conditionId'])
                if m_data and 'YES' in m_data and 'NO' in m_data:
                    arb = calculate_arbitrage_guaranteed(m_data['YES']['price'], m_data['NO']['price'], 100.0)
                    if arb:
                        ARBI_CACHE.append({"title": e.get('title')[:30], "yes_id": m_data['YES']['id'], "no_id": m_data['NO']['id'], "p_y": m_data['YES']['price'], "p_n": m_data['NO']['price'], "roi": arb['roi']})
        except: continue
    return len(ARBI_CACHE) > 0

# --- 4. TELEGRAM INTERFACE ---
async def start(update, context):
    btns = [['🚀 START ARBI-SCAN', '📊 CALIBRATE'], ['💳 VAULT', '🔧 FIX APPROVAL']]
    await update.message.reply_text(f"{LOGO}\n<b>HYDRA ACTIVE.</b>", reply_markup=ReplyKeyboardMarkup(btns, resize_keyboard=True), parse_mode='HTML')

async def main_handler(update, context):
    cmd = update.message.text
    if 'START ARBI-SCAN' in cmd:
        m = await update.message.reply_text("📡 <b>SCANNING MATRIX...</b>", parse_mode='HTML')
        if await scour_arbitrage():
            kb = [[InlineKeyboardButton(f"🎯 {a['title']} ({a['roi']}%)", callback_data=f"ARB_{i}")] for i, a in enumerate(ARBI_CACHE[:8])]
            await m.edit_text("<b>OPPORTUNITIES:</b>", reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')
        else: await m.edit_text("🛰 <b>EMPTY GRID.</b>")
    
    elif 'VAULT' in cmd:
        funder = os.getenv("FUNDER_ADDRESS", vault.address)
        bal = usdc_e_contract.functions.balanceOf(funder).call()
        await update.message.reply_text(f"<b>VAULT</b>\n<code>{funder}</code>\n<b>USDC.e:</b> ${bal/1e6:.2f}", parse_mode='HTML')

async def handle_query(update, context):
    q = update.callback_query; await q.answer()
    stake = float(context.user_data.get('stake', 10))
    
    if "ARB_" in q.data:
        target = ARBI_CACHE[int(q.data.split("_")[1])]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        msg = f"<b>{target['title']}</b>\n✅ YES: ${calc['stake_yes']}\n❌ NO: ${calc['stake_no']}\n💰 ROI: {calc['roi']}%"
        kb = [[InlineKeyboardButton("🔥 EXECUTE", callback_data=f"EXE_{q.data.split('_')[1]}")]]
        await q.edit_message_text(msg, reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')
        
    elif "EXE_" in q.data:
        target = ARBI_CACHE[int(q.data.split("_")[1])]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        results = []
        for (t_id, amt) in [(target['yes_id'], calc['stake_yes']), (target['no_id'], calc['stake_no'])]:
            try:
                price_limit = await get_safe_price(t_id)
                # THE FIX: Ensuring 'amount' is used and price is non-zero
                order_args = MarketOrderArgs(token_id=str(t_id), amount=float(amt), side=BUY, price=price_limit)
                signed = clob_client.create_order(order_args)
                resp = clob_client.post_order(signed, OrderType.FOK)
                results.append(True if (resp.get("success") or "order_id" in resp) else False)
            except Exception as e:
                await context.bot.send_message(q.message.chat_id, f"❌ <b>SDK Error:</b> {str(e)}")
                results.append(False)
        await context.bot.send_message(q.message.chat_id, "✅ <b>STRIKE COMPLETE</b>" if all(results) else "⚠️ <b>PARTIAL FILL / REVERT</b>", parse_mode='HTML')

if __name__ == "__main__":
    app = ApplicationBuilder().token(os.getenv("TELEGRAM_BOT_TOKEN")).build()
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CallbackQueryHandler(handle_query))
    app.add_handler(MessageHandler(filters.TEXT & (~filters.COMMAND), main_handler))
